import React, { useEffect } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import * as yup from "yup";
import { useFormik } from "formik";
import { useDispatch, useSelector } from "react-redux";
import { Button } from "antd";
import { Save, ArrowLeft, Layers, Tag, FolderPlus, ShieldCheck, ChevronRight } from "lucide-react";
import {
  createCategory,
  getAProductCategory,
  resetState,
  updateAProductCategory,
} from "../features/pcategory/pcategorySlice";

let schema = yup.object().shape({
  title: yup.string().required("Category Name is Required"),
});

export default function Addcat() {
  const dispatch = useDispatch();
  const location = useLocation();
  const getPCatId = location.pathname.split("/")[3];
  const navigate = useNavigate();

  const newCategory = useSelector((state) => state.pCategory);
  const {
    isSuccess,
    isError,
    isLoading,
    createdCategory,
    categoryName,
    updatedCategory,
  } = newCategory;

  useEffect(() => {
    if (getPCatId !== undefined) {
      dispatch(getAProductCategory(getPCatId));
    } else {
      dispatch(resetState());
    }
  }, [getPCatId, dispatch]);

  useEffect(() => {
    if (isSuccess && createdCategory) {
      toast.success("Protocol Initialized: Category Registry Updated");
      dispatch(resetState());
      navigate("../list-category");
    }
    if (isSuccess && updatedCategory) {
      toast.success("Revision Committed: Classification Updated");
      dispatch(resetState());
      navigate("../list-category");
    }
    if (isError) {
      toast.error("Process Breach: Classification Failure");
    }
  }, [isSuccess, isError, isLoading, navigate, createdCategory, updatedCategory, dispatch]);

  const formik = useFormik({
    enableReinitialize: true,
    initialValues: {
      title: categoryName || "",
    },
    validationSchema: schema,
    onSubmit: (values) => {
      if (getPCatId !== undefined) {
        dispatch(updateAProductCategory({ id: getPCatId, pCatData: values }));
      } else {
        dispatch(createCategory(values));
      }
    },
  });

  return (
    <div className="min-h-screen pb-20 animate-in fade-in slide-in-from-bottom-8 duration-1000">
      {/* Command Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 mb-12">
        <div className="space-y-3">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-2 h-2 rounded-full bg-blue-600 animate-ping" />
            <span className="text-[11px] font-black text-blue-600 uppercase tracking-[0.4em]">
              {getPCatId !== undefined ? "Revision Protocol" : "Initialization Sequence"}
            </span>
          </div>
          <h1 className="text-[48px] md:text-[64px] font-black text-slate-900 tracking-tighter leading-[0.9] italic">
            {getPCatId !== undefined ? "Modify" : "Create"} <span className="text-blue-600">Category</span>
          </h1>
          <p className="text-[16px] text-slate-400 font-bold max-w-xl leading-relaxed">
            Defining core ontological nodes for the commercial product hierarchy and global indexing.
          </p>
        </div>

        <Button
          onClick={() => navigate(-1)}
          icon={<ArrowLeft size={18} />}
          className="h-14 px-8 flex items-center gap-3 rounded-[22px] border-none bg-slate-50 hover:bg-slate-100 text-slate-500 font-black uppercase text-[11px] tracking-widest shadow-sm hover:shadow-md transition-all active:scale-95"
        >
          Abort Protocol
        </Button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
        <div className="lg:col-span-8">
          <div className="enterprise-card p-8 md:p-12 overflow-hidden relative">
            <div className="absolute top-0 right-0 w-64 h-64 bg-blue-500/5 rounded-full blur-3xl -mr-32 -mt-32" />
            
            <form onSubmit={formik.handleSubmit} className="space-y-10 relative z-10">
              <div className="space-y-6">
                <div className="flex items-center gap-4 mb-4">
                  <div className="w-10 h-10 rounded-xl bg-slate-900 flex items-center justify-center text-white shadow-lg">
                    <Tag size={20} />
                  </div>
                  <div>
                    <h3 className="text-[18px] font-black text-slate-900 tracking-tight uppercase">Base Parameters</h3>
                    <p className="text-[12px] text-slate-400 font-bold uppercase tracking-widest">Entry designation for the node registry</p>
                  </div>
                </div>

                <div className="relative group">
                   <div className="absolute top-5 left-6 text-slate-300 group-focus-within:text-blue-600 transition-colors z-20">
                     <Layers size={22} />
                   </div>
                   <input
                     type="text"
                     name="title"
                     onChange={formik.handleChange("title")}
                     onBlur={formik.handleBlur("title")}
                     value={formik.values.title}
                     placeholder="Designate Category Name..."
                     className={`w-full h-20 pl-16 pr-8 bg-slate-50/50 border-2 rounded-[28px] text-[18px] font-black placeholder:text-slate-200 focus:outline-none transition-all duration-500 ${
                       formik.touched.title && formik.errors.title
                         ? "border-rose-100 bg-rose-50/30 text-rose-600"
                         : "border-slate-50 focus:border-blue-500 focus:bg-white focus:shadow-2xl focus:shadow-blue-500/5"
                     }`}
                   />
                   
                   {formik.touched.title && formik.errors.title && (
                     <div className="flex items-center gap-2 pl-6 mt-4 animate-in slide-in-from-top-2">
                        <div className="w-1.5 h-1.5 rounded-full bg-rose-500 animate-pulse" />
                        <p className="text-rose-500 text-[10px] uppercase font-black tracking-widest">
                          {formik.errors.title}
                        </p>
                     </div>
                   )}
                </div>
              </div>

              <div className="pt-8 border-t border-slate-50">
                <div className="flex flex-col md:flex-row gap-6">
                   <Button
                      type="primary"
                      htmlType="submit"
                      loading={isLoading}
                      size="large"
                      icon={<Save size={20} />}
                      className="bg-slate-900 hover:bg-blue-600 rounded-[28px] h-20 font-black text-[13px] uppercase tracking-[0.25em] shadow-2xl shadow-slate-900/20 hover:shadow-blue-500/40 border-none transition-all flex-1 flex items-center justify-center gap-4 group active:scale-[0.97]"
                    >
                      {getPCatId !== undefined ? "Commit System Revision" : "Initialize Domain Node"}
                   </Button>
                </div>
              </div>
            </form>
          </div>

          <div className="mt-8 flex items-center justify-center gap-3 opacity-30 grayscale hover:grayscale-0 transition-all duration-500">
             <ShieldCheck size={16} />
             <span className="text-[10px] font-black uppercase tracking-[0.3em]">Encrypted Pulse Core Transmission</span>
          </div>
        </div>

        <div className="lg:col-span-4 space-y-6">
           <div className="enterprise-card p-10 bg-slate-900 text-white border-none shadow-2xl shadow-slate-900/30 relative overflow-hidden group">
              <div className="absolute top-0 right-0 w-48 h-48 bg-blue-500/20 rounded-full blur-3xl -mr-24 -mt-24 group-hover:bg-blue-500/30 transition-all duration-700" />
              <div className="relative z-10 space-y-8">
                 <div className="w-14 h-14 rounded-2xl bg-white/10 flex items-center justify-center backdrop-blur-md">
                    <FolderPlus size={28} className="text-blue-400" />
                 </div>
                 <div>
                    <h4 className="text-[20px] font-black italic tracking-tighter mb-2">Protocol Brief</h4>
                    <p className="text-slate-400 font-bold text-[14px] leading-relaxed">
                      Categories form the primary taxonomic layer. Every product must be mapped to exactly one category node for proper indexing and discovery within the Pulse Network.
                    </p>
                 </div>
                 <div className="space-y-4">
                    <div className="flex items-center gap-3 p-4 rounded-2xl bg-white/5 border border-white/5">
                       <ChevronRight size={14} className="text-blue-500" />
                       <span className="text-[11px] font-black uppercase tracking-widest text-slate-300">Global Unique Identification</span>
                    </div>
                    <div className="flex items-center gap-3 p-4 rounded-2xl bg-white/5 border border-white/5">
                       <ChevronRight size={14} className="text-blue-500" />
                       <span className="text-[11px] font-black uppercase tracking-widest text-slate-300">Schema Validation Level 4</span>
                    </div>
                 </div>
              </div>
           </div>
        </div>
      </div>

      <style>{`
        .enterprise-card {
            background: #ffffff;
            border-radius: 40px;
            border: 1.5px solid #f8fafc;
            box-shadow: 0 15px 40px rgba(0,0,0,0.02);
            transition: all 0.6s cubic-bezier(0.2, 1, 0.2, 1);
        }
      `}</style>
    </div>
  );
}
